#!/bin/bash

set -euo pipefail

if [[ $(id -u) != 0 ]]; then
  echo "This script must be run as root" >&2
  exit 1
fi

echo "Restricting read access to the kernel message buffer..."

# Create a new SELinux policy that restricts read access to the kernel message buffer
cat <<EOF | sudo tee /etc/selinux/targeted/policy/local/kernel-message-buffer.te >/dev/null
module kernel-message-buffer 1.0;

require {
    type init_t;
    class file read;
}

# Only allow privileged users to read the kernel message buffer
allow init_t self:file read;
EOF

# Reload the SELinux policy
sudo semodule -i /etc/selinux/targeted/policy/local/kernel-message-buffer.te

echo "Done!"

